163→func readTranscriptOffset(path string) transcriptOffset {
164→	data, err := os.ReadFile(path)
165→	if err != nil {
166→		return transcriptOffset{}
167→	}
168→	var offset transcriptOffset
169→	if err := json.Unmarshal(data, &offset); err != nil {
170→		return transcriptOffset{}
171→	}
172→	return offset
173→}
174→
175→func writeTranscriptOffset(path string, offset transcriptOffset) error {
176→	if err := os.MkdirAll(filepath.Dir(path), 0o700); err != nil {
177→		return err
178→	}
179→	data, err := json.Marshal(offset)
180→	if err != nil {
181→		return err
182→	}
183→	return os.WriteFile(path, data, 0o600)
184→}
185→
186→// trimTranscriptHistory trims already-checkpointed entries from a cumulative
187→// kiro transcript using a stored offset. Returns the re-serialized trimmed
188→// JSON and true if trimming was applied, or (nil, false) if the full
189→// transcript should be used as-is.
190→func (a *Agent) trimTranscriptHistory(raw []byte) ([]byte, bool) {
191→	parsed, err := parseTranscript(raw)
192→	if err != nil || len(parsed.History) == 0 {
193→		return nil, false
194→	}
195→
196→	offsetPath := a.transcriptOffsetPath()
197→	prev := readTranscriptOffset(offsetPath)
198→	totalLen := len(parsed.History)
199→
200→	trimFrom := 0
201→	if prev.ConversationID == parsed.ConversationID && prev.Position > 0 && prev.Position <= totalLen {
202→		trimFrom = prev.Position
203→	}
204→
205→	// Only update offset when there are new entries to capture.
206→	if trimFrom < totalLen {
207→		_ = writeTranscriptOffset(offsetPath, transcriptOffset{
208→			ConversationID: parsed.ConversationID,
209→			Position:       totalLen,
210→		})
211→	}
212→
213→	if trimFrom == 0 || trimFrom >= totalLen {
214→		// No trimming needed (first capture) or no new entries since last
215→		// capture. Return full transcript so the caller always has content —
216→		// an empty transcript would cause the CLI finalize step to fail.
217→		return nil, false
218→	}
219→
220→	parsed.History = parsed.History[trimFrom:]
221→	filtered, err := json.Marshal(parsed)
222→	if err != nil {
223→		return nil, false
224→	}
225→	return filtered, true
226→}
