312→func (a *Agent) captureTranscriptForStop(cwd string, sessionID string, conversationID string) string {
313→	// Try IDE workspace sessions first — the stop hook is fired by the IDE,
314→	// so IDE data is the most accurate source. CLI DB is a fallback for
315→	// kiro-cli (non-IDE) sessions where no IDE workspace data exists.
316→	if sessionRef, err := a.ensureIDETranscript(cwd, sessionID); err == nil && sessionRef != "" {
317→		return sessionRef
318→	}
319→	if sessionRef, err := a.ensureCachedTranscript(cwd, sessionID, conversationID); err == nil && sessionRef != "" {
320→		return sessionRef
321→	}
322→	return a.createPlaceholderTranscript(cwd, sessionID)
323→}
