336→func (a *Agent) cacheTranscriptPath(cwd string, sessionID string) (string, error) {
337→	repoRoot := protocol.RepoRoot()
338→	if repoRoot == "" {
339→		repoRoot = cwd
340→	}
341→	sessionDir, err := a.GetSessionDir(repoRoot)
342→	if err != nil {
343→		return "", err
344→	}
345→	if err := os.MkdirAll(sessionDir, 0o700); err != nil {
346→		return "", fmt.Errorf("failed to create cache dir: %w", err)
347→	}
348→	return a.ResolveSessionFile(sessionDir, sessionID), nil
