351→func kiroDataDir() (string, error) {
352→	home, err := os.UserHomeDir()
353→	if err != nil {
354→		return "", fmt.Errorf("failed to get home directory: %w", err)
355→	}
356→	switch runtime.GOOS {
357→	case "darwin":
358→		return filepath.Join(home, "Library", "Application Support"), nil
359→	default:
360→		return filepath.Join(home, ".local", "share"), nil
361→	}
