372→func ideWorkspaceSessionsDir(cwd string) (string, error) {
373→	home, err := os.UserHomeDir()
374→	if err != nil {
375→		return "", fmt.Errorf("failed to get home directory: %w", err)
376→	}
377→
378→	// Kiro IDE uses standard base64 with '=' padding replaced by '_'.
379→	encoded := strings.ReplaceAll(base64.StdEncoding.EncodeToString([]byte(cwd)), "=", "_")
380→	switch runtime.GOOS {
381→	case "darwin":
382→		return filepath.Join(home, "Library", "Application Support", "Kiro", "User", "globalStorage", "kiro.kiroagent", "workspace-sessions", encoded), nil
383→	default:
384→		return filepath.Join(home, ".config", "Kiro", "User", "globalStorage", "kiro.kiroagent", "workspace-sessions", encoded), nil
385→	}
386→}
