392→func (a *Agent) GetTranscriptPosition(path string) (int, error) {
393→	transcript, err := readAndParseTranscript(path)
394→	if errors.Is(err, os.ErrNotExist) {
395→		return 0, nil
396→	}
397→	if err != nil {
398→		return 0, err
399→	}
400→	return len(transcript.History), nil
