403→func (a *Agent) ExtractModifiedFiles(path string, offset int) ([]string, int, error) {
404→	transcript, err := readAndParseTranscript(path)
405→	if errors.Is(err, os.ErrNotExist) {
406→		return nil, 0, nil
407→	}
408→	if err != nil {
409→		return nil, 0, err
410→	}
411→
412→	totalEntries := len(transcript.History)
413→	if offset >= totalEntries {
414→		return nil, totalEntries, nil
415→	}
416→
417→	return extractModifiedFilesFromHistory(transcript.History[offset:]), totalEntries, nil
418→}
