420→func (a *Agent) ExtractPrompts(path string, offset int) ([]string, error) {
421→	transcript, err := readAndParseTranscript(path)
422→	if errors.Is(err, os.ErrNotExist) {
423→		return nil, nil
424→	}
425→	if err != nil {
426→		return nil, err
427→	}
428→
429→	var prompts []string
430→	for i := offset; i < len(transcript.History); i++ {
431→		if prompt := extractUserPrompt(transcript.History[i].User.Content); prompt != "" {
432→			prompts = append(prompts, prompt)
433→		}
434→	}
435→	return prompts, nil
436→}
