451→func readAndParseTranscript(path string) (*kiroTranscript, error) {
452→	data, err := os.ReadFile(path)
453→	if err != nil {
454→		return nil, err
455→	}
456→	return parseTranscript(data)
457→}
458→
459→func parseTranscript(data []byte) (*kiroTranscript, error) {
460→	if len(data) == 0 {
461→		return &kiroTranscript{}, nil
462→	}
463→
464→	var transcript kiroTranscript
465→	if err := json.Unmarshal(data, &transcript); err != nil {
466→		return nil, fmt.Errorf("failed to parse kiro transcript: %w", err)
467→	}
468→	if isCLITranscript(&transcript) {
469→		return &transcript, nil
470→	}
471→
472→	if converted := tryParseIDETranscript(data); converted != nil {
473→		return converted, nil
474→	}
475→
476→	return &transcript, nil
477→}
478→
479→func isCLITranscript(transcript *kiroTranscript) bool {
480→	if len(transcript.History) == 0 {
481→		return false
482→	}
483→	return len(transcript.History[0].User.Content) > 0 || len(transcript.History[0].Assistant) > 0
484→}
485→
486→func tryParseIDETranscript(data []byte) *kiroTranscript {
487→	var ide kiroIDETranscript
488→	if err := json.Unmarshal(data, &ide); err != nil {
489→		return nil
490→	}
491→	if len(ide.History) == 0 || ide.History[0].Message.Role == "" {
492→		return nil
493→	}
494→	return convertIDETranscript(&ide)
495→}
496→
497→func convertIDETranscript(ide *kiroIDETranscript) *kiroTranscript {
498→	transcript := &kiroTranscript{}
499→
500→	var pendingUser *kiroIDEHistoryEntry
501→	for i := range ide.History {
502→		entry := &ide.History[i]
503→		switch entry.Message.Role {
504→		case "user":
505→			if pendingUser != nil {
506→				transcript.History = append(transcript.History, ideEntryToPaired(pendingUser, nil))
507→			}
508→			pendingUser = entry
509→		case "assistant":
510→			transcript.History = append(transcript.History, ideEntryToPaired(pendingUser, entry))
511→			pendingUser = nil
512→		}
513→	}
514→
515→	if pendingUser != nil {
516→		transcript.History = append(transcript.History, ideEntryToPaired(pendingUser, nil))
517→	}
518→
519→	return transcript
520→}
521→
522→func ideEntryToPaired(user, assistant *kiroIDEHistoryEntry) kiroHistoryEntry {
523→	entry := kiroHistoryEntry{}
524→
525→	if user != nil {
526→		prompt := extractIDEText(user.Message.Content, true)
527→		if prompt != "" {
528→			content, err := json.Marshal(kiroPromptContent{
529→				Prompt: struct {
530→					Prompt string `json:"prompt"`
531→				}{Prompt: prompt},
532→			})
533→			if err == nil {
534→				entry.User.Content = content
535→			}
536→		} else {
537→			entry.User.Content = user.Message.Content
538→		}
539→	}
540→
541→	if assistant != nil {
542→		text := extractIDEText(assistant.Message.Content, false)
543→		if text != "" {
544→			content, err := json.Marshal(kiroResponseContent{
545→				Response: kiroResponsePayload{Content: text},
546→			})
547→			if err == nil {
548→				entry.Assistant = content
549→			}
550→		} else {
551→			entry.Assistant = assistant.Message.Content
552→		}
553→	}
554→
555→	return entry
556→}
557→
558→// extractIDEText extracts text from a json.RawMessage that may be either a
559→// plain string or an array of content blocks. When blocksFirst is true, it
560→// tries to parse as blocks before falling back to a plain string (user
561→// messages); otherwise it tries plain string first (assistant messages).
562→func extractIDEText(content json.RawMessage, blocksFirst bool) string {
563→	if len(content) == 0 {
564→		return ""
565→	}
566→
567→	tryBlocks := func() string {
568→		var blocks []kiroIDEContentBlock
569→		if err := json.Unmarshal(content, &blocks); err == nil && len(blocks) > 0 {
570→			for _, block := range blocks {
571→				if block.Type == "text" && block.Text != "" {
572→					return block.Text
573→				}
574→			}
575→		}
576→		return ""
577→	}
578→
579→	tryString := func() string {
580→		var text string
581→		if err := json.Unmarshal(content, &text); err == nil {
582→			return text
583→		}
584→		return ""
585→	}
586→
587→	if blocksFirst {
588→		if s := tryBlocks(); s != "" {
589→			return s
590→		}
591→		return tryString()
592→	}
593→	if s := tryString(); s != "" {
594→		return s
595→	}
596→	return tryBlocks()
597→}
598→
599→func extractUserPrompt(content json.RawMessage) string {
600→	if len(content) == 0 {
601→		return ""
602→	}
603→
604→	var promptContent kiroPromptContent
605→	if err := json.Unmarshal(content, &promptContent); err == nil && promptContent.Prompt.Prompt != "" {
606→		return promptContent.Prompt.Prompt
607→	}
608→	return ""
609→}
