611→func extractModifiedFilesFromHistory(entries []kiroHistoryEntry) []string {
612→	seen := make(map[string]bool)
613→	var files []string
614→
615→	for i := range entries {
616→		for _, path := range extractFilesFromAssistant(entries[i].Assistant) {
617→			if path == "" || seen[path] {
618→				continue
619→			}
620→			seen[path] = true
621→			files = append(files, path)
622→		}
623→	}
624→
625→	return files
626→}
627→
628→func extractFilesFromAssistant(raw json.RawMessage) []string {
629→	if len(raw) == 0 {
630→		return nil
631→	}
632→
633→	var toolUseContent kiroToolUseContent
634→	if err := json.Unmarshal(raw, &toolUseContent); err != nil || len(toolUseContent.ToolUse.ToolUses) == 0 {
635→		return nil
636→	}
637→
638→	var paths []string
639→	for _, call := range toolUseContent.ToolUse.ToolUses {
640→		if !isFileModificationTool(call.Name) {
641→			continue
642→		}
643→		if path := extractFilePath(call.Args); path != "" {
644→			paths = append(paths, path)
645→		}
646→	}
647→	return paths
648→}
649→
650→func isFileModificationTool(name string) bool {
651→	_, ok := kiroFileModificationTools[name]
652→	return ok
653→}
654→
655→func extractFilePath(args json.RawMessage) string {
656→	if len(args) == 0 {
657→		return ""
658→	}
659→
660→	var fields map[string]json.RawMessage
661→	if err := json.Unmarshal(args, &fields); err != nil {
662→		return ""
663→	}
664→
665→	for _, key := range []string{"path", "file_path", "filename"} {
666→		raw, ok := fields[key]
667→		if !ok {
668→			continue
669→		}
670→		var path string
671→		if err := json.Unmarshal(raw, &path); err == nil && path != "" {
672→			return path
