111→func (a *Agent) InstallHooks(localDev bool, force bool) (int, error) {
112→	repoRoot := protocol.RepoRoot()
113→	if !force && allHooksInstalled(repoRoot, localDev) && trustedCommandsPresent(repoRoot, localDev) {
114→		return 0, nil
115→	}
116→
117→	if err := writeCLIHooks(repoRoot, localDev); err != nil {
118→		return 0, err
119→	}
120→	if err := writeIDEHooks(repoRoot, localDev); err != nil {
121→		return 0, err
122→	}
123→	if err := installTrustedCommands(repoRoot, localDev); err != nil {
124→		return 0, err
125→	}
126→
127→	return len(defaultHookNames()) + len(ideHookDefs), nil
128→}
