306→func installTrustedCommands(repoRoot string, localDev bool) error {
307→	settingsPath := filepath.Join(repoRoot, vscodeSettingsDir, vscodeSettingsFile)
308→
309→	settings, err := readSettings(settingsPath)
310→	if err != nil {
311→		return err
312→	}
313→	commands, err := readTrustedCommands(settings)
314→	if err != nil {
315→		return err
316→	}
317→	want := trustedCommand(localDev)
318→	for _, command := range commands {
319→		if command == want {
320→			return nil
321→		}
322→	}
323→	commands = append(commands, want)
324→	raw, err := json.Marshal(commands)
325→	if err != nil {
326→		return err
327→	}
328→	settings[trustedCommandsKey] = raw
329→	return writeSettings(settingsPath, settings)
330→}
331→
332→func uninstallTrustedCommands(repoRoot string) error {
333→	settingsPath := filepath.Join(repoRoot, vscodeSettingsDir, vscodeSettingsFile)
334→	if _, err := os.Stat(settingsPath); err != nil {
335→		if os.IsNotExist(err) {
336→			return nil
337→		}
338→		return err
339→	}
340→	settings, err := readSettings(settingsPath)
341→	if err != nil {
342→		return err
343→	}
344→	commands, err := readTrustedCommands(settings)
345→	if err != nil {
346→		return err
347→	}
348→	filtered := commands[:0]
349→	for _, command := range commands {
350→		if command != prodTrustedCommand && command != localDevTrustedCmd {
351→			filtered = append(filtered, command)
352→		}
353→	}
354→	if len(filtered) == 0 {
355→		delete(settings, trustedCommandsKey)
356→	} else {
357→		raw, err := json.Marshal(filtered)
358→		if err != nil {
359→			return err
360→		}
361→		settings[trustedCommandsKey] = raw
362→	}
363→	return writeSettings(settingsPath, settings)
364→}
