407→func readTrustedCommands(settings map[string]json.RawMessage) ([]string, error) {
408→	raw, ok := settings[trustedCommandsKey]
409→	if !ok {
410→		return []string{}, nil
411→	}
412→	var commands []string
413→	if err := json.Unmarshal(raw, &commands); err != nil {
414→		return nil, err
415→	}
416→	return commands, nil
417→}
