460→func (a *Agent) appendToolCall(name string, input json.RawMessage) {
461→	call := kiroToolCall{Name: name, Args: input}
462→	line, err := json.Marshal(call)
463→	if err != nil {
464→		return
465→	}
466→	path := a.toolCallsPath()
467→	if err := os.MkdirAll(filepath.Dir(path), 0o700); err != nil {
468→		return
469→	}
470→	f, err := os.OpenFile(path, os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0o600)
