478→func (a *Agent) readAndClearToolCalls() []kiroToolCall {
479→	path := a.toolCallsPath()
480→	data, err := os.ReadFile(path)
481→	if err != nil {
482→		return nil
483→	}
484→	_ = os.Remove(path)
485→
486→	var calls []kiroToolCall
487→	for _, line := range strings.Split(strings.TrimSpace(string(data)), "\n") {
488→		if line == "" {
489→			continue
490→		}
491→		var call kiroToolCall
492→		if err := json.Unmarshal([]byte(line), &call); err == nil {
493→			calls = append(calls, call)
494→		}
495→	}
496→	return calls
497→}
