595→// buildTranscript creates a kiro CLI transcript with the given number of prompt entries.
596→func buildTranscript(convID string, numPrompts int) []byte {
597→	var entries []kiroHistoryEntry
598→	for i := range numPrompts {
599→		promptJSON, _ := json.Marshal(kiroPromptContent{
600→			Prompt: struct {
601→				Prompt string `json:"prompt"`
602→			}{Prompt: fmt.Sprintf("prompt %d", i)},
603→		})
604→		entries = append(entries, kiroHistoryEntry{
605→			User: kiroUserMessage{Content: promptJSON},
606→		})
607→	}
608→	transcript := kiroTranscript{ConversationID: convID, History: entries}
609→	data, _ := json.Marshal(transcript)
610→	return data
611→}
