  1→package kiro
  2→
  3→import (
  4→	"fmt"
  5→	"os"
  6→	"path/filepath"
  7→	"time"
  8→
  9→	"github.com/entireio/external-agents/agents/entire-agent-kiro/internal/protocol"
 10→)
 11→
 12→type Agent struct{}
 13→
 14→func New() *Agent {
 15→	return &Agent{}
 16→}
 17→
 18→func (a *Agent) Info() protocol.InfoResponse {
 19→	return protocol.InfoResponse{
 20→		ProtocolVersion: protocol.ProtocolVersion,
 21→		Name:            "kiro",
 22→		Type:            "Kiro",
 23→		Description:     "Kiro - External agent plugin for Entire CLI",
 24→		IsPreview:       true,
 25→		ProtectedDirs:   []string{".kiro"},
 26→		HookNames: []string{
 27→			HookNameAgentSpawn,
 28→			HookNameUserPromptSubmit,
 29→			HookNamePreToolUse,
 30→			HookNamePostToolUse,
 31→			HookNameStop,
 32→		},
 33→		Capabilities: protocol.DeclaredCapabilities{
 34→			Hooks:              true,
 35→			TranscriptAnalyzer: true,
 36→			UsesTerminal:       true,
 37→		},
 38→	}
 39→}
 40→
 41→func (a *Agent) Detect() protocol.DetectResponse {
 42→	repoRoot := protocol.RepoRoot()
 43→	_, err := os.Stat(filepath.Join(repoRoot, ".kiro"))
 44→	return protocol.DetectResponse{Present: err == nil}
 45→}
 46→
 47→func (a *Agent) GetSessionID(input *protocol.HookInputJSON) string {
 48→	if input != nil && input.SessionID != "" {
 49→		return input.SessionID
 50→	}
 51→	return "stub-session-000"
 52→}
 53→
 54→func (a *Agent) ReadSession(input *protocol.HookInputJSON) (protocol.AgentSessionJSON, error) {
 55→	sessionID := a.GetSessionID(input)
 56→	repoRoot := protocol.RepoRoot()
 57→	sessionDir, err := a.GetSessionDir(repoRoot)
 58→	if err != nil {
 59→		return protocol.AgentSessionJSON{}, err
 60→	}
 61→	sessionRef := ""
 62→	if input != nil && input.SessionRef != "" {
 63→		sessionRef = input.SessionRef
 64→	} else {
 65→		sessionRef = a.ResolveSessionFile(sessionDir, sessionID)
 66→	}
 67→
 68→	var nativeData []byte
 69→	if sessionRef != "" {
 70→		data, err := os.ReadFile(sessionRef)
 71→		if err != nil {
 72→			return protocol.AgentSessionJSON{}, fmt.Errorf("failed to read transcript: %w", err)
 73→		}
 74→		nativeData = data
 75→	}
 76→
 77→	return protocol.AgentSessionJSON{
 78→		SessionID:     sessionID,
 79→		AgentName:     "kiro",
 80→		RepoPath:      repoRoot,
 81→		SessionRef:    sessionRef,
 82→		StartTime:     time.Now().UTC().Format(time.RFC3339),
 83→		NativeData:    nativeData,
 84→		ModifiedFiles: []string{},
 85→		NewFiles:      []string{},
 86→		DeletedFiles:  []string{},
 87→	}, nil
 88→}
 89→
 90→func (a *Agent) WriteSession(session protocol.AgentSessionJSON) error {
 91→	if session.SessionRef == "" {
 92→		return nil
 93→	}
 94→	if err := os.MkdirAll(filepath.Dir(session.SessionRef), 0o700); err != nil {
 95→		return err
 96→	}
 97→	return os.WriteFile(session.SessionRef, session.NativeData, 0o600)
 98→}
 99→
100→func (a *Agent) FormatResumeCommand(_ string) string {
101→	return "kiro-cli chat --resume"
102→}
