  1→package kiro
  2→
  3→import (
  4→	"crypto/rand"
  5→	"encoding/hex"
  6→	"encoding/json"
  7→	"fmt"
  8→	"os"
  9→	"path/filepath"
 10→	"strings"
 11→	"time"
 12→
 13→	"github.com/entireio/external-agents/agents/entire-agent-kiro/internal/protocol"
 14→)
 15→
 16→const (
 17→	hooksFileName       = "entire.json"
 18→	hooksDir            = "agents"
 19→	ideHooksDir         = "hooks"
 20→	ideHookFileSuffix   = ".kiro.hook"
 21→	ideHookVersion      = "1"
 22→	vscodeSettingsDir   = ".vscode"
 23→	vscodeSettingsFile  = "settings.json"
 24→	trustedCommandsKey  = "kiroAgent.trustedCommands"
 25→	prodTrustedCommand  = "sh -c 'entire hooks *"
 26→	localDevCommandBase = "go run ${KIRO_PROJECT_DIR}/cmd/entire/main.go hooks kiro "
 27→	localDevTrustedCmd  = "sh -c 'go run ${KIRO_PROJECT_DIR}/cmd/entire/main.go hooks *"
 28→	prodHookCommandBase = "entire hooks kiro "
 29→	sessionIDFile  = "kiro-active-session"
 30→	toolCallsFile  = "kiro-tool-calls.jsonl"
 31→)
 32→
 33→type ideHookDef struct {
 34→	Filename    string
 35→	TriggerType string
 36→	CLIVerb     string
 37→}
 38→
 39→var ideHookDefs = []ideHookDef{
 40→	{Filename: "entire-prompt-submit", TriggerType: "promptSubmit", CLIVerb: HookNameUserPromptSubmit},
 41→	{Filename: "entire-stop", TriggerType: "agentStop", CLIVerb: HookNameStop},
 42→	{Filename: "entire-pre-tool-use", TriggerType: "preToolUse", CLIVerb: HookNamePreToolUse},
 43→	{Filename: "entire-post-tool-use", TriggerType: "postToolUse", CLIVerb: HookNamePostToolUse},
 44→}
 45→
 46→func (a *Agent) ParseHook(hookName string, input []byte) (*protocol.EventJSON, error) {
 47→	var raw hookInputRaw
 48→	if len(input) > 0 {
 49→		if err := json.Unmarshal(input, &raw); err != nil {
 50→			return nil, err
 51→		}
 52→	}
 53→
 54→	switch hookName {
 55→	case HookNameAgentSpawn:
 56→		sessionID := a.generateAndCacheSessionID()
 57→		return &protocol.EventJSON{
 58→			Type:      1,
 59→			SessionID: sessionID,
 60→			Timestamp: time.Now().UTC().Format(time.RFC3339),
 61→		}, nil
 62→	case HookNameUserPromptSubmit:
 63→		sessionID := a.readCachedSessionID()
 64→		if sessionID == "" {
 65→			sessionID = a.generateAndCacheSessionID()
 66→		}
 67→		prompt := raw.Prompt
 68→		if prompt == "" {
 69→			prompt = os.Getenv("USER_PROMPT")
 70→		}
 71→		return &protocol.EventJSON{
 72→			Type:      2,
 73→			SessionID: sessionID,
 74→			Prompt:    prompt,
 75→			Timestamp: time.Now().UTC().Format(time.RFC3339),
 76→		}, nil
 77→	case HookNamePreToolUse:
 78→		return nil, nil
 79→	case HookNamePostToolUse:
 80→		if raw.ToolName != "" {
 81→			a.appendToolCall(raw.ToolName, raw.ToolInput)
 82→		}
 83→		return nil, nil
 84→	case HookNameStop:
 85→		cwd := raw.CWD
 86→		if cwd == "" {
 87→			cwd = protocol.RepoRoot()
 88→		}
 89→		sessionID := a.readCachedSessionID()
 90→		conversationID, _ := a.querySessionID(cwd)
 91→		if sessionID == "" {
 92→			if conversationID != "" {
 93→				sessionID = conversationID
 94→			} else {
 95→				sessionID = fallbackStopSessionID()
 96→			}
 97→		}
 98→		sessionRef := a.captureTranscriptForStop(cwd, sessionID, conversationID)
 99→		a.clearCachedSessionID()
100→		return &protocol.EventJSON{
101→			Type:       3,
102→			SessionID:  sessionID,
103→			SessionRef: sessionRef,
104→			Timestamp:  time.Now().UTC().Format(time.RFC3339),
105→		}, nil
106→	default:
107→		return nil, nil
108→	}
109→}
110→
111→func (a *Agent) InstallHooks(localDev bool, force bool) (int, error) {
112→	repoRoot := protocol.RepoRoot()
113→	if !force && allHooksInstalled(repoRoot, localDev) && trustedCommandsPresent(repoRoot, localDev) {
114→		return 0, nil
115→	}
116→
117→	if err := writeCLIHooks(repoRoot, localDev); err != nil {
118→		return 0, err
119→	}
120→	if err := writeIDEHooks(repoRoot, localDev); err != nil {
121→		return 0, err
122→	}
123→	if err := installTrustedCommands(repoRoot, localDev); err != nil {
124→		return 0, err
125→	}
126→
127→	return len(defaultHookNames()) + len(ideHookDefs), nil
128→}
129→
130→func (a *Agent) UninstallHooks() error {
131→	repoRoot := protocol.RepoRoot()
132→	cliPath := filepath.Join(repoRoot, ".kiro", hooksDir, hooksFileName)
133→	if err := os.Remove(cliPath); err != nil && !os.IsNotExist(err) {
134→		return err
135→	}
136→	for _, def := range ideHookDefs {
137→		path := filepath.Join(repoRoot, ".kiro", ideHooksDir, def.Filename+ideHookFileSuffix)
138→		if err := os.Remove(path); err != nil && !os.IsNotExist(err) {
139→			return err
140→		}
141→	}
142→	if err := uninstallTrustedCommands(repoRoot); err != nil {
143→		return err
144→	}
145→	return nil
146→}
147→
148→func (a *Agent) AreHooksInstalled() bool {
149→	repoRoot := protocol.RepoRoot()
150→	if _, err := os.Stat(filepath.Join(repoRoot, ".kiro", "agents", "entire.json")); err == nil {
151→		return true
152→	}
153→	if _, err := os.Stat(filepath.Join(repoRoot, ".kiro", "hooks", "entire-stop.kiro.hook")); err == nil {
154→		return true
155→	}
156→	return false
157→}
158→
159→func defaultHookNames() []string {
160→	return []string{
161→		HookNameAgentSpawn,
162→		HookNameUserPromptSubmit,
163→		HookNamePreToolUse,
164→		HookNamePostToolUse,
165→		HookNameStop,
166→	}
167→}
168→
169→func writeCLIHooks(repoRoot string, localDev bool) error {
170→	hooksPath := filepath.Join(repoRoot, ".kiro", hooksDir, hooksFileName)
171→	if err := os.MkdirAll(filepath.Dir(hooksPath), 0o700); err != nil {
172→		return err
173→	}
174→	commandBase := hookCommandBase(localDev)
175→
176→	file := kiroAgentFile{
177→		Name: "entire",
178→		Tools: []string{
179→			"read", "write", "shell", "grep", "glob",
180→			"aws", "report", "introspect", "knowledge",
181→			"thinking", "todo", "delegate",
182→		},
183→		Hooks: kiroHooks{
184→			AgentSpawn:       []kiroHookEntry{{Command: commandBase + HookNameAgentSpawn}},
185→			UserPromptSubmit: []kiroHookEntry{{Command: commandBase + HookNameUserPromptSubmit}},
186→			PreToolUse:       []kiroHookEntry{{Command: commandBase + HookNamePreToolUse}},
187→			PostToolUse:      []kiroHookEntry{{Command: commandBase + HookNamePostToolUse}},
188→			Stop:             []kiroHookEntry{{Command: commandBase + HookNameStop}},
189→		},
190→	}
191→
192→	data, err := marshalJSON(file)
193→	if err != nil {
194→		return err
195→	}
196→	return os.WriteFile(hooksPath, data, 0o600)
197→}
198→
199→func writeIDEHooks(repoRoot string, localDev bool) error {
200→	dir := filepath.Join(repoRoot, ".kiro", ideHooksDir)
201→	if err := os.MkdirAll(dir, 0o700); err != nil {
202→		return err
203→	}
204→	commandBase := hookCommandBase(localDev)
205→
206→	for _, def := range ideHookDefs {
207→		hook := kiroIDEHookFile{
208→			Enabled:     true,
209→			Name:        def.Filename,
210→			Description: "Entire CLI " + def.TriggerType + " hook",
211→			Version:     ideHookVersion,
212→			When: kiroIDEHookWhen{
213→				Type: def.TriggerType,
214→			},
215→			Then: kiroIDEHookThen{
216→				Type:    "runCommand",
217→				Command: shellWrappedCommand(commandBase + def.CLIVerb),
218→			},
219→		}
220→		data, err := marshalJSON(hook)
221→		if err != nil {
222→			return err
223→		}
224→		path := filepath.Join(dir, def.Filename+ideHookFileSuffix)
225→		if err := os.WriteFile(path, data, 0o600); err != nil {
226→			return err
227→		}
228→	}
229→
230→	return nil
231→}
232→
233→func allHooksInstalled(repoRoot string, localDev bool) bool {
234→	cliPath := filepath.Join(repoRoot, ".kiro", hooksDir, hooksFileName)
235→	commandBase := hookCommandBase(localDev)
236→	if data, err := os.ReadFile(cliPath); err == nil {
237→		var file kiroAgentFile
238→		if json.Unmarshal(data, &file) == nil &&
239→			hookCommandExists(file.Hooks.AgentSpawn, commandBase+HookNameAgentSpawn) &&
240→			hookCommandExists(file.Hooks.UserPromptSubmit, commandBase+HookNameUserPromptSubmit) &&
241→			hookCommandExists(file.Hooks.PreToolUse, commandBase+HookNamePreToolUse) &&
242→			hookCommandExists(file.Hooks.PostToolUse, commandBase+HookNamePostToolUse) &&
243→			hookCommandExists(file.Hooks.Stop, commandBase+HookNameStop) &&
244→			allIDEHooksPresent(repoRoot, localDev) {
245→			return true
246→		}
247→	}
248→	return false
249→}
250→
251→func hookCommandExists(entries []kiroHookEntry, command string) bool {
252→	for _, entry := range entries {
253→		if entry.Command == command {
254→			return true
255→		}
256→	}
257→	return false
258→}
259→
260→func allIDEHooksPresent(repoRoot string, localDev bool) bool {
261→	commandBase := hookCommandBase(localDev)
262→	for _, def := range ideHookDefs {
263→		path := filepath.Join(repoRoot, ".kiro", ideHooksDir, def.Filename+ideHookFileSuffix)
264→		data, err := os.ReadFile(path)
265→		if err != nil {
266→			return false
267→		}
268→		var hook kiroIDEHookFile
269→		if err := json.Unmarshal(data, &hook); err != nil {
270→			return false
271→		}
272→		if hook.Then.Command != shellWrappedCommand(commandBase+def.CLIVerb) {
273→			return false
274→		}
275→	}
276→	return true
277→}
278→
279→func trustedCommandsPresent(repoRoot string, localDev bool) bool {
280→	settingsPath := filepath.Join(repoRoot, vscodeSettingsDir, vscodeSettingsFile)
281→	data, err := os.ReadFile(settingsPath)
282→	if err != nil {
283→		return false
284→	}
285→	var settings map[string]json.RawMessage
286→	if err := json.Unmarshal(data, &settings); err != nil {
287→		return false
288→	}
289→	raw, ok := settings[trustedCommandsKey]
290→	if !ok {
291→		return false
292→	}
293→	var commands []string
294→	if err := json.Unmarshal(raw, &commands); err != nil {
295→		return false
296→	}
297→	want := trustedCommand(localDev)
298→	for _, command := range commands {
299→		if command == want {
300→			return true
301→		}
302→	}
303→	return false
304→}
305→
306→func installTrustedCommands(repoRoot string, localDev bool) error {
307→	settingsPath := filepath.Join(repoRoot, vscodeSettingsDir, vscodeSettingsFile)
308→
309→	settings, err := readSettings(settingsPath)
310→	if err != nil {
311→		return err
312→	}
313→	commands, err := readTrustedCommands(settings)
314→	if err != nil {
