100→func (a *Agent) ensureCachedTranscript(cwd string, sessionID string, conversationID string) (string, error) {
101→	db, err := kiroCLIDataDBPath()
102→	if err != nil {
103→		return "", err
104→	}
105→	if _, err := os.Stat(db); err != nil {
106→		return "", fmt.Errorf("kiro database not found at %s: %w", db, err)
107→	}
108→
109→	var query string
110→	if conversationID != "" {
111→		query = fmt.Sprintf(
112→			"SELECT value FROM conversations_v2 WHERE json_extract(value, '$.conversation_id') = '%s' ORDER BY updated_at DESC LIMIT 1",
113→			escapeSQLString(conversationID),
114→		)
115→	} else {
116→		query = fmt.Sprintf(
117→			"SELECT value FROM conversations_v2 WHERE key = '%s' ORDER BY updated_at DESC LIMIT 1",
118→			escapeSQLString(cwd),
119→		)
120→	}
121→
122→	out, err := runSQLiteCommand(db, query)
123→	if err != nil {
124→		return "", fmt.Errorf("sqlite3 transcript query failed: %w", err)
125→	}
126→
127→	raw := strings.TrimSpace(string(out))
128→	if raw == "" {
129→		return "", errors.New("no transcript found")
130→	}
131→
132→	cachePath, err := a.cacheTranscriptPath(cwd, sessionID)
133→	if err != nil {
134→		return "", err
135→	}
136→
137→	data := []byte(raw)
138→	if filtered, ok := a.trimTranscriptHistory([]byte(raw)); ok {
139→		data = filtered
140→	}
141→
142→	// If the transcript has no history (e.g., offset trimmed everything),
143→	// return error so captureTranscriptForStop can try other sources (IDE).
144→	if parsed, parseErr := parseTranscript(data); parseErr == nil && len(parsed.History) == 0 {
145→		return "", errors.New("CLI transcript has no history entries")
146→	}
147→
148→	if err := os.WriteFile(cachePath, data, 0o600); err != nil {
149→		return "", fmt.Errorf("failed to write cached transcript: %w", err)
150→	}
151→	return cachePath, nil
152→}
