314→	// so IDE data is the most accurate source. CLI DB is a fallback for
315→	// kiro-cli (non-IDE) sessions where no IDE workspace data exists.
316→	if sessionRef, err := a.ensureIDETranscript(cwd, sessionID); err == nil && sessionRef != "" {
