611→func extractModifiedFilesFromHistory(entries []kiroHistoryEntry) []string {
612→	seen := make(map[string]bool)
613→	var files []string
614→
615→	for i := range entries {
616→		for _, path := range extractFilesFromAssistant(entries[i].Assistant) {
617→			if path == "" || seen[path] {
618→				continue
619→			}
620→			seen[path] = true
621→			files = append(files, path)
622→		}
623→	}
624→
625→	return files
626→}
