628→func extractFilesFromAssistant(raw json.RawMessage) []string {
629→	if len(raw) == 0 {
630→		return nil
631→	}
632→
633→	var toolUseContent kiroToolUseContent
634→	if err := json.Unmarshal(raw, &toolUseContent); err != nil || len(toolUseContent.ToolUse.ToolUses) == 0 {
635→		return nil
636→	}
