+	for _, line := range strings.Split(strings.TrimSpace(string(data)), "\n") {
+		if line == "" {
+			continue
+		}
+		var call kiroToolCall
+		if err := json.Unmarshal([]byte(line), &call); err == nil {
+			calls = append(calls, call)
+		}
+	}
+	return calls
+}
