 38→func (a *Agent) ChunkTranscript(content []byte, maxSize int) ([][]byte, error) {
 39→	if maxSize <= 0 {
 40→		return nil, errors.New("max-size must be greater than zero")
 41→	}
 42→	if len(content) == 0 {
 43→		return [][]byte{[]byte{}}, nil
 44→	}
 45→
 46→	var chunks [][]byte
 47→	for start := 0; start < len(content); start += maxSize {
 48→		end := start + maxSize
 49→		if end > len(content) {
 50→			end = len(content)
 51→		}
 52→		chunk := make([]byte, end-start)
 53→		copy(chunk, content[start:end])
 54→		chunks = append(chunks, chunk)
 55→	}
 56→	return chunks, nil
 57→}
