163→func readTranscriptOffset(path string) transcriptOffset {
164→	data, err := os.ReadFile(path)
165→	if err != nil {
166→		return transcriptOffset{}
167→	}
168→	var offset transcriptOffset
169→	if err := json.Unmarshal(data, &offset); err != nil {
170→		return transcriptOffset{}
171→	}
172→	return offset
173→}
174→
175→func writeTranscriptOffset(path string, offset transcriptOffset) error {
176→	if err := os.MkdirAll(filepath.Dir(path), 0o700); err != nil {
177→		return err
178→	}
179→	data, err := json.Marshal(offset)
180→	if err != nil {
181→		return err
182→	}
183→	return os.WriteFile(path, data, 0o600)
184→}
