228→func (a *Agent) ensureIDETranscript(cwd string, sessionID string) (string, error) {
229→	sessionsDir, err := ideWorkspaceSessionsDir(cwd)
230→	if err != nil {
231→		return "", err
232→	}
233→
234→	indexPath := filepath.Join(sessionsDir, "sessions.json")
235→	indexData, err := os.ReadFile(indexPath)
236→	if err != nil {
237→		return "", fmt.Errorf("IDE sessions.json not found: %w", err)
238→	}
239→
240→	var sessions []ideSessionIndexEntry
241→	if err := json.Unmarshal(indexData, &sessions); err != nil {
242→		return "", fmt.Errorf("failed to parse IDE sessions.json: %w", err)
243→	}
244→	if len(sessions) == 0 {
245→		return "", errors.New("no IDE sessions found")
246→	}
247→
248→	sort.Slice(sessions, func(i, j int) bool {
249→		return sessions[i].DateCreated > sessions[j].DateCreated
250→	})
251→
252→	ideSessionID := sessions[0].SessionID
253→	if !filepath.IsLocal(ideSessionID + ".json") {
254→		return "", fmt.Errorf("invalid session ID: %q", ideSessionID)
255→	}
256→
257→	transcriptPath := filepath.Join(sessionsDir, ideSessionID+".json")
258→	transcriptData, err := os.ReadFile(transcriptPath)
259→	if err != nil {
260→		return "", fmt.Errorf("failed to read IDE transcript %s: %w", transcriptPath, err)
261→	}
262→
263→	// Merge captured tool calls (from post-tool-use hooks) into the IDE
264→	// transcript. The IDE format only stores text summaries ("On it."), so
265→	// tool call details would be lost without this enrichment.
266→	data := transcriptData
267→	if toolCalls := a.readAndClearToolCalls(); len(toolCalls) > 0 {
268→		if enriched := enrichIDETranscriptWithToolCalls(transcriptData, toolCalls); enriched != nil {
269→			data = enriched
270→		}
271→	}
272→
273→	cachePath, err := a.cacheTranscriptPath(cwd, sessionID)
274→	if err != nil {
275→		return "", err
276→	}
277→	if err := os.WriteFile(cachePath, data, 0o600); err != nil {
278→		return "", fmt.Errorf("failed to write cached IDE transcript: %w", err)
279→	}
280→	return cachePath, nil
281→}
