628→func extractFilesFromAssistant(raw json.RawMessage) []string {
629→	if len(raw) == 0 {
630→		return nil
631→	}
632→
633→	var toolUseContent kiroToolUseContent
634→	if err := json.Unmarshal(raw, &toolUseContent); err != nil || len(toolUseContent.ToolUse.ToolUses) == 0 {
635→		return nil
636→	}
637→
638→	var paths []string
639→	for _, call := range toolUseContent.ToolUse.ToolUses {
640→		if !isFileModificationTool(call.Name) {
641→			continue
642→		}
643→		if path := extractFilePath(call.Args); path != "" {
644→			paths = append(paths, path)
645→		}
646→	}
647→	return paths
648→}
