678→func extractLastAssistantResponse(entries []kiroHistoryEntry) string {
679→	for i := len(entries) - 1; i >= 0; i-- {
680→		if len(entries[i].Assistant) == 0 {
681→			continue
682→		}
683→
684→		var responseContent kiroResponseContent
685→		if err := json.Unmarshal(entries[i].Assistant, &responseContent); err == nil && responseContent.Response.Content != "" {
686→			return responseContent.Response.Content
687→		}
688→	}
689→	return ""
690→}
