172→		return err
173→	}
174→	commandBase := hookCommandBase(localDev)
175→
176→	file := kiroAgentFile{
177→		Name: "entire",
178→		Tools: []string{
179→			"read", "write", "shell", "grep", "glob",
180→			"aws", "report", "introspect", "knowledge",
181→			"thinking", "todo", "delegate",
182→		},
183→		Hooks: kiroHooks{
184→			AgentSpawn:       []kiroHookEntry{{Command: commandBase + HookNameAgentSpawn}},
185→			UserPromptSubmit: []kiroHookEntry{{Command: commandBase + HookNameUserPromptSubmit}},
186→			PreToolUse:       []kiroHookEntry{{Command: commandBase + HookNamePreToolUse}},
187→			PostToolUse:      []kiroHookEntry{{Command: commandBase + HookNamePostToolUse}},
188→			Stop:             []kiroHookEntry{{Command: commandBase + HookNameStop}},
189→		},
190→	}
