373→// shellWrappedCommand wraps a hook command in "sh -c" with a /dev/null stdin
374→// redirect. IDEs typically run hook commands directly without a shell, so a
375→// bare "</dev/null" suffix is passed as a literal argument instead of being
376→// interpreted as a redirect. Wrapping in sh ensures the redirect works.
377→// The command content is built from compile-time constants (not user input).
378→func shellWrappedCommand(cmd string) string {
379→	return "sh -c '" + cmd + " </dev/null'"
380→}
