	}
	if len(chunks) < 2 {
		t.Fatalf("expected multiple chunks, got %d", len(chunks))
	}
	for i, chunk := range chunks {
		if len(chunk) > 8 {
			t.Fatalf("chunk %d length = %d, want <= 8", i, len(chunk))
