	default:
		return filepath.Join(home, ".config", "Kiro", "User", "globalStorage", "kiro.kiroagent"), nil
	}
}

// extractIDESessionID parses the sessionId from an IDE session JSON file.
func extractIDESessionID(data []byte) string {
