480→	return parseTranscript(data)
481→}
482→
483→func parseTranscript(data []byte) (*kiroTranscript, error) {
484→	if len(data) == 0 {
485→		return &kiroTranscript{}, nil
486→	}
487→
488→	var transcript kiroTranscript
489→	if err := json.Unmarshal(data, &transcript); err != nil {
490→		return nil, fmt.Errorf("failed to parse kiro transcript: %w", err)
491→	}
492→	if isCLITranscript(&transcript) {
493→		return &transcript, nil
494→	}
495→
496→	if converted := tryParseIDETranscript(data); converted != nil {
497→		return converted, nil
498→	}
499→
500→	return &transcript, nil
501→}
502→
503→func isCLITranscript(transcript *kiroTranscript) bool {
504→	if len(transcript.History) == 0 {
505→		return false
506→	}
507→	return len(transcript.History[0].User.Content) > 0 || len(transcript.History[0].Assistant) > 0
508→}
509→
510→func tryParseIDETranscript(data []byte) *kiroTranscript {
511→	var ide kiroIDETranscript
512→	if err := json.Unmarshal(data, &ide); err != nil {
513→		return nil
514→	}
515→	if len(ide.History) == 0 || ide.History[0].Message.Role == "" {
516→		return nil
517→	}
518→	return convertIDETranscript(&ide)
519→}
520→
521→func convertIDETranscript(ide *kiroIDETranscript) *kiroTranscript {
522→	transcript := &kiroTranscript{}
523→
524→	var pendingUser *kiroIDEHistoryEntry
525→	for i := range ide.History {
526→		entry := &ide.History[i]
527→		switch entry.Message.Role {
528→		case "user":
529→			if pendingUser != nil {
530→				transcript.History = append(transcript.History, ideEntryToPaired(pendingUser, nil))
531→			}
532→			pendingUser = entry
533→		case "assistant":
534→			transcript.History = append(transcript.History, ideEntryToPaired(pendingUser, entry))
535→			pendingUser = nil
536→		}
537→	}
538→
539→	if pendingUser != nil {
540→		transcript.History = append(transcript.History, ideEntryToPaired(pendingUser, nil))
541→	}
542→
543→	return transcript
544→}
545→
546→func ideEntryToPaired(user, assistant *kiroIDEHistoryEntry) kiroHistoryEntry {
547→	entry := kiroHistoryEntry{}
548→
549→	if user != nil {
550→		prompt := extractIDEText(user.Message.Content, true)
551→		if prompt != "" {
552→			content, err := json.Marshal(kiroPromptContent{
553→				Prompt: struct {
554→					Prompt string `json:"prompt"`
555→				}{Prompt: prompt},
556→			})
557→			if err == nil {
558→				entry.User.Content = content
559→			}
560→		} else {
561→			entry.User.Content = user.Message.Content
562→		}
563→	}
564→
565→	if assistant != nil {
566→		text := extractIDEText(assistant.Message.Content, false)
567→		if text != "" {
568→			content, err := json.Marshal(kiroResponseContent{
569→				Response: kiroResponsePayload{Content: text},
570→			})
571→			if err == nil {
572→				entry.Assistant = content
573→			}
574→		} else {
575→			entry.Assistant = assistant.Message.Content
576→		}
577→	}
578→
579→	return entry
580→}
581→
582→// extractIDEText extracts text from a json.RawMessage that may be either a
583→// plain string or an array of content blocks. When blocksFirst is true, it
584→// tries to parse as blocks before falling back to a plain string (user
585→// messages); otherwise it tries plain string first (assistant messages).
586→func extractIDEText(content json.RawMessage, blocksFirst bool) string {
587→	if len(content) == 0 {
588→		return ""
589→	}
590→
591→	tryBlocks := func() string {
592→		var blocks []kiroIDEContentBlock
593→		if err := json.Unmarshal(content, &blocks); err == nil && len(blocks) > 0 {
594→			for _, block := range blocks {
595→				if block.Type == "text" && block.Text != "" {
596→					return block.Text
597→				}
598→			}
599→		}
600→		return ""
601→	}
602→
603→	tryString := func() string {
604→		var text string
605→		if err := json.Unmarshal(content, &text); err == nil {
606→			return text
607→		}
608→		return ""
609→	}
610→
611→	if blocksFirst {
612→		if s := tryBlocks(); s != "" {
613→			return s
614→		}
615→		return tryString()
616→	}
617→	if s := tryString(); s != "" {
618→		return s
619→	}
620→	return tryBlocks()
621→}
622→
623→func extractUserPrompt(content json.RawMessage) string {
624→	if len(content) == 0 {
625→		return ""
626→	}
627→
628→	var promptContent kiroPromptContent
629→	if err := json.Unmarshal(content, &promptContent); err == nil && promptContent.Prompt.Prompt != "" {
630→		return promptContent.Prompt.Prompt
631→	}
632→	return ""
633→}
