723→		return "", err
724→	}
725→	switch runtime.GOOS {
726→	case "darwin":
727→		return filepath.Join(home, "Library", "Application Support", "Kiro", "User", "globalStorage", "kiro.kiroagent"), nil
728→	default:
729→		return filepath.Join(home, ".config", "Kiro", "User", "globalStorage", "kiro.kiroagent"), nil
730→	}
