744→// extractIDEExecutionIDs parses executionId values from assistant entries
745→// in an IDE session JSON file.
746→func extractIDEExecutionIDs(data []byte) []string {
747→	var meta kiroIDESessionMeta
748→	if err := json.Unmarshal(data, &meta); err != nil {
749→		return nil
750→	}
