760→// findExecutionLogsForSession scans Kiro IDE workspace directories to find
761→// execution log files matching the given chat session ID. Returns a map of
762→// executionId → *kiroExecutionLog.
763→func findExecutionLogsForSession(chatSessionID string) (map[string]*kiroExecutionLog, error) {
764→	baseDir, err := ideExecutionLogsBaseDir()
765→	if err != nil {
766→		return nil, err
767→	}
768→
769→	entries, err := os.ReadDir(baseDir)
770→	if err != nil {
771→		return nil, err
772→	}
773→
774→	for _, entry := range entries {
775→		if !entry.IsDir() || len(entry.Name()) != 32 {
776→			continue
777→		}
778→		logsDir := filepath.Join(baseDir, entry.Name(), execLogsSubdir)
779→		if _, err := os.Stat(logsDir); err != nil {
780→			continue
781→		}
782→		logs := scanExecutionLogsDir(logsDir, chatSessionID)
783→		if len(logs) > 0 {
784→			return logs, nil
785→		}
786→	}
787→
788→	return map[string]*kiroExecutionLog{}, nil
789→}
790→
791→// scanExecutionLogsDir reads all execution log files in a directory and returns
792→// those matching the given chat session ID.
793→func scanExecutionLogsDir(dir string, chatSessionID string) map[string]*kiroExecutionLog {
794→	files, err := os.ReadDir(dir)
795→	if err != nil {
796→		return nil
797→	}
798→
799→	result := make(map[string]*kiroExecutionLog)
800→	for _, f := range files {
801→		if f.IsDir() {
802→			continue
803→		}
804→		data, err := os.ReadFile(filepath.Join(dir, f.Name()))
805→		if err != nil {
806→			continue
807→		}
808→		var log kiroExecutionLog
809→		if err := json.Unmarshal(data, &log); err != nil {
810→			continue
811→		}
812→		if log.ChatSessionID == chatSessionID {
813→			logCopy := log
814→			result[log.ExecutionID] = &logCopy
815→		}
816→	}
817→	return result
818→}
819→
820→// convertExecutionActionsToHistoryEntries converts Kiro IDE execution log
821→// actions into CLI transcript history entries. Tool-modifying actions (create,
822→// edit) become ToolUse entries; say actions become Response entries.
823→func convertExecutionActionsToHistoryEntries(actions []kiroExecutionAction) []kiroHistoryEntry {
824→	var toolCalls []kiroToolCall
825→	var entries []kiroHistoryEntry
826→
827→	for _, action := range actions {
828→		if toolName, ok := execActionToToolName[action.ActionType]; ok {
829→			filePath := extractExecActionFilePath(action.Input)
830→			if filePath != "" {
831→				args, _ := json.Marshal(map[string]string{"path": filePath})
832→				toolCalls = append(toolCalls, kiroToolCall{
833→					Name: toolName,
834→					Args: args,
835→				})
836→			}
837→		}
838→		if action.ActionType == "say" {
839→			var out struct {
840→				Message string `json:"message"`
841→			}
842→			if err := json.Unmarshal(action.Output, &out); err == nil && out.Message != "" {
843→				// Flush any pending tool calls first
844→				if len(toolCalls) > 0 {
845→					toolUseJSON, _ := json.Marshal(kiroToolUseContent{
846→						ToolUse: kiroToolUsePayload{ToolUses: toolCalls},
847→					})
848→					entries = append(entries, kiroHistoryEntry{Assistant: toolUseJSON})
849→					toolCalls = nil
850→				}
851→				responseJSON, _ := json.Marshal(kiroResponseContent{
852→					Response: kiroResponsePayload{Content: out.Message},
853→				})
854→				entries = append(entries, kiroHistoryEntry{Assistant: responseJSON})
855→			}
856→		}
857→	}
858→
859→	// Flush remaining tool calls without a trailing say
860→	if len(toolCalls) > 0 {
861→		toolUseJSON, _ := json.Marshal(kiroToolUseContent{
862→			ToolUse: kiroToolUsePayload{ToolUses: toolCalls},
863→		})
864→		entries = append(entries, kiroHistoryEntry{Assistant: toolUseJSON})
865→	}
866→
867→	return entries
868→}
869→
870→// extractExecActionFilePath extracts the file path from an execution log
871→// action's input JSON (used by create/edit actions).
872→func extractExecActionFilePath(input json.RawMessage) string {
873→	if len(input) == 0 {
874→		return ""
875→	}
876→	var fields struct {
877→		File string `json:"file"`
878→	}
879→	if err := json.Unmarshal(input, &fields); err != nil {
880→		return ""
881→	}
882→	return fields.File
883→}
884→
885→// enrichIDETranscriptWithExecutionLogs converts an IDE transcript to CLI
886→// format and replaces "On it." assistant entries with actual data from
887→// execution logs. Returns the re-serialized CLI-format JSON, or nil if
888→// conversion fails.
889→func enrichIDETranscriptWithExecutionLogs(ideData []byte, execLogs map[string]*kiroExecutionLog) []byte {
890→	var meta kiroIDESessionMeta
891→	if err := json.Unmarshal(ideData, &meta); err != nil {
892→		return nil
893→	}
894→
895→	// Also parse the IDE transcript for the basic user/assistant pairing
896→	var ide kiroIDETranscript
897→	if err := json.Unmarshal(ideData, &ide); err != nil {
898→		return nil
899→	}
900→
901→	// Build an executionId→index mapping from the meta history
902→	execIDMap := make(map[int]string) // IDE history index → executionId
903→	for i, entry := range meta.History {
904→		if entry.ExecutionID != "" {
905→			execIDMap[i] = entry.ExecutionID
906→		}
907→	}
908→
909→	// Convert to CLI format, enriching assistant entries from execution logs
910→	transcript := &kiroTranscript{}
911→	var pendingUser *kiroIDEHistoryEntry
912→	for i := range ide.History {
913→		entry := &ide.History[i]
914→		switch entry.Message.Role {
915→		case "user":
916→			if pendingUser != nil {
917→				transcript.History = append(transcript.History, ideEntryToPaired(pendingUser, nil))
918→			}
919→			pendingUser = entry
920→		case "assistant":
921→			execID := execIDMap[i]
922→			if execID != "" {
923→				if execLog, ok := execLogs[execID]; ok {
924→					// Replace with execution log data
925→					userEntry := ideEntryToPaired(pendingUser, nil)
926→					assistantEntries := convertExecutionActionsToHistoryEntries(execLog.Actions)
927→					if len(assistantEntries) > 0 {
928→						// First entry gets the user prompt
929→						userEntry.Assistant = assistantEntries[0].Assistant
930→						transcript.History = append(transcript.History, userEntry)
931→						// Additional entries (if tool calls + response) get appended
932→						for _, extra := range assistantEntries[1:] {
933→							transcript.History = append(transcript.History, extra)
934→						}
935→						pendingUser = nil
936→						continue
937→					}
938→				}
939→			}
940→			// Fallback: use the IDE text as-is
941→			transcript.History = append(transcript.History, ideEntryToPaired(pendingUser, entry))
942→			pendingUser = nil
943→		}
944→	}
945→	if pendingUser != nil {
946→		transcript.History = append(transcript.History, ideEntryToPaired(pendingUser, nil))
947→	}
948→
949→	result, err := json.Marshal(transcript)
950→	if err != nil {
951→		return nil
952→	}
953→	return result
954→}
