279→func trustedCommandsPresent(repoRoot string, localDev bool) bool {
280→	settingsPath := filepath.Join(repoRoot, vscodeSettingsDir, vscodeSettingsFile)
281→	data, err := os.ReadFile(settingsPath)
282→	if err != nil {
283→		return false
284→	}
285→	var settings map[string]json.RawMessage
286→	if err := json.Unmarshal(data, &settings); err != nil {
287→		return false
288→	}
289→	raw, ok := settings[trustedCommandsKey]
290→	if !ok {
291→		return false
292→	}
293→	var commands []string
294→	if err := json.Unmarshal(raw, &commands); err != nil {
295→		return false
296→	}
297→	want := trustedCommand(localDev)
298→	for _, command := range commands {
299→		if command == want {
300→			return true
301→		}
302→	}
303→	return false
