306→func installTrustedCommands(repoRoot string, localDev bool) error {
307→	settingsPath := filepath.Join(repoRoot, vscodeSettingsDir, vscodeSettingsFile)
308→
309→	settings, err := readSettings(settingsPath)
310→	if err != nil {
311→		return err
312→	}
313→	commands, err := readTrustedCommands(settings)
314→	if err != nil {
315→		return err
316→	}
317→	want := trustedCommand(localDev)
318→	for _, command := range commands {
319→		if command == want {
320→			return nil
321→		}
322→	}
323→	commands = append(commands, want)
324→	raw, err := json.Marshal(commands)
325→	if err != nil {
326→		return err
327→	}
328→	settings[trustedCommandsKey] = raw
329→	return writeSettings(settingsPath, settings)
330→}
