332→func uninstallTrustedCommands(repoRoot string) error {
333→	settingsPath := filepath.Join(repoRoot, vscodeSettingsDir, vscodeSettingsFile)
334→	if _, err := os.Stat(settingsPath); err != nil {
335→		if os.IsNotExist(err) {
336→			return nil
337→		}
338→		return err
339→	}
340→	settings, err := readSettings(settingsPath)
341→	if err != nil {
342→		return err
343→	}
344→	commands, err := readTrustedCommands(settings)
345→	if err != nil {
346→		return err
347→	}
348→	filtered := commands[:0]
349→	for _, command := range commands {
350→		if command != prodTrustedCommand && command != localDevTrustedCmd {
351→			filtered = append(filtered, command)
352→		}
353→	}
354→	if len(filtered) == 0 {
355→		delete(settings, trustedCommandsKey)
356→	} else {
357→		raw, err := json.Marshal(filtered)
358→		if err != nil {
359→			return err
360→		}
361→		settings[trustedCommandsKey] = raw
362→	}
363→	return writeSettings(settingsPath, settings)
364→}
