389→func readSettings(path string) (map[string]json.RawMessage, error) {
390→	data, err := os.ReadFile(path)
391→	if err != nil {
392→		if os.IsNotExist(err) {
393→			return map[string]json.RawMessage{}, nil
394→		}
395→		return nil, err
396→	}
397→	var settings map[string]json.RawMessage
398→	if err := json.Unmarshal(data, &settings); err != nil {
399→		return nil, err
400→	}
401→	if settings == nil {
402→		settings = map[string]json.RawMessage{}
403→	}
404→	return settings, nil
405→}
