419→func writeSettings(path string, settings map[string]json.RawMessage) error {
420→	if err := os.MkdirAll(filepath.Dir(path), 0o700); err != nil {
421→		return err
422→	}
423→	data, err := marshalJSON(settings)
424→	if err != nil {
425→		return err
426→	}
427→	return os.WriteFile(path, data, 0o600)
428→}
