198→// trimTranscriptHistory trims already-checkpointed entries from a cumulative
199→// kiro transcript using a stored offset. Returns the re-serialized trimmed
200→// JSON and true if trimming was applied, or (nil, false) if the full
201→// transcript should be used as-is.
202→func (a *Agent) trimTranscriptHistory(raw []byte) ([]byte, bool) {
203→	parsed, err := parseTranscript(raw)
204→	if err != nil || len(parsed.History) == 0 {
205→		return nil, false
206→	}
207→
208→	offsetPath := a.transcriptOffsetPath()
209→	prev := readTranscriptOffset(offsetPath)
210→	totalLen := len(parsed.History)
211→
212→	trimFrom := 0
213→	if prev.ConversationID == parsed.ConversationID && prev.Position > 0 && prev.Position <= totalLen {
214→		trimFrom = prev.Position
215→	}
216→
217→	// Only update offset when there are new entries to capture.
218→	if trimFrom < totalLen {
219→		_ = writeTranscriptOffset(offsetPath, transcriptOffset{
220→			ConversationID: parsed.ConversationID,
221→			Position:       totalLen,
222→		})
223→	}
224→
225→	if trimFrom == 0 || trimFrom >= totalLen {
226→		// No trimming needed (first capture) or no new entries since last
227→		// capture. Return full transcript so the caller always has content —
228→		// an empty transcript would cause the CLI finalize step to fail.
229→		return nil, false
230→	}
231→
232→	parsed.History = parsed.History[trimFrom:]
233→	filtered, err := json.Marshal(parsed)
234→	if err != nil {
235→		return nil, false
236→	}
237→	return filtered, true
238→}
