240→func (a *Agent) ensureIDETranscript(cwd string, sessionID string) (string, error) {
241→	sessionsDir, err := ideWorkspaceSessionsDir(cwd)
242→	if err != nil {
243→		return "", err
244→	}
245→
246→	indexPath := filepath.Join(sessionsDir, "sessions.json")
247→	indexData, err := os.ReadFile(indexPath)
248→	if err != nil {
249→		return "", fmt.Errorf("IDE sessions.json not found: %w", err)
250→	}
251→
252→	var sessions []ideSessionIndexEntry
253→	if err := json.Unmarshal(indexData, &sessions); err != nil {
254→		return "", fmt.Errorf("failed to parse IDE sessions.json: %w", err)
255→	}
256→	if len(sessions) == 0 {
257→		return "", errors.New("no IDE sessions found")
258→	}
259→
260→	sort.Slice(sessions, func(i, j int) bool {
261→		return sessions[i].DateCreated > sessions[j].DateCreated
262→	})
263→
264→	ideSessionID := sessions[0].SessionID
265→	if !filepath.IsLocal(ideSessionID + ".json") {
266→		return "", fmt.Errorf("invalid session ID: %q", ideSessionID)
267→	}
268→
269→	transcriptPath := filepath.Join(sessionsDir, ideSessionID+".json")
270→	transcriptData, err := os.ReadFile(transcriptPath)
271→	if err != nil {
272→		return "", fmt.Errorf("failed to read IDE transcript %s: %w", transcriptPath, err)
273→	}
274→
275→	// Enrich the IDE transcript with actual agent responses and tool calls.
276→	// The IDE session format only stores "On it." as assistant content.
277→	//
278→	// Priority 1: Read Kiro IDE execution logs — these contain the full
279→	// action trace (tool calls, responses, file modifications).
280→	// Priority 2: Merge tool calls from post-tool-use hook JSONL file.
281→	data := transcriptData
282→	if chatSessionID := extractIDESessionID(transcriptData); chatSessionID != "" {
283→		if execLogs, err := findExecutionLogsForSession(chatSessionID); err == nil && len(execLogs) > 0 {
284→			if enriched := enrichIDETranscriptWithExecutionLogs(transcriptData, execLogs); enriched != nil {
285→				data = enriched
286→			}
287→		}
288→	}
289→	if bytes.Equal(data, transcriptData) {
290→		if toolCalls := a.readAndClearToolCalls(); len(toolCalls) > 0 {
291→			if enriched := enrichIDETranscriptWithToolCalls(transcriptData, toolCalls); enriched != nil {
292→				data = enriched
293→			}
294→		}
295→	}
296→
297→	cachePath, err := a.cacheTranscriptPath(cwd, sessionID)
298→	if err != nil {
299→		return "", err
300→	}
301→	if err := os.WriteFile(cachePath, data, 0o600); err != nil {
302→		return "", fmt.Errorf("failed to write cached IDE transcript: %w", err)
303→	}
304→	return cachePath, nil
305→}
306→
307→// enrichIDETranscriptWithToolCalls converts an IDE transcript to CLI format
308→// and injects the captured tool calls into the last assistant entry. Returns
309→// the re-serialized CLI-format JSON, or nil if conversion fails.
310→func enrichIDETranscriptWithToolCalls(ideData []byte, toolCalls []kiroToolCall) []byte {
311→	converted := tryParseIDETranscript(ideData)
312→	if converted == nil || len(converted.History) == 0 {
313→		return nil
314→	}
315→
316→	// Assign all tool calls to the last assistant entry, since post-tool-use
317→	// hooks fire between user-prompt-submit and stop for the current turn.
318→	toolUse := kiroToolUseContent{
319→		ToolUse: kiroToolUsePayload{ToolUses: toolCalls},
320→	}
321→	toolUseJSON, err := json.Marshal(toolUse)
322→	if err != nil {
323→		return nil
324→	}
325→
326→	lastIdx := len(converted.History) - 1
327→	converted.History[lastIdx].Assistant = toolUseJSON
328→
329→	result, err := json.Marshal(converted)
330→	if err != nil {
331→		return nil
332→	}
333→	return result
334→}
