582→// extractIDEText extracts text from a json.RawMessage that may be either a
583→// plain string or an array of content blocks. When blocksFirst is true, it
584→// tries to parse as blocks before falling back to a plain string (user
585→// messages); otherwise it tries plain string first (assistant messages).
586→func extractIDEText(content json.RawMessage, blocksFirst bool) string {
587→	if len(content) == 0 {
588→		return ""
589→	}
590→
591→	tryBlocks := func() string {
592→		var blocks []kiroIDEContentBlock
593→		if err := json.Unmarshal(content, &blocks); err == nil && len(blocks) > 0 {
594→			for _, block := range blocks {
595→				if block.Type == "text" && block.Text != "" {
596→					return block.Text
597→				}
598→			}
599→		}
600→		return ""
601→	}
602→
603→	tryString := func() string {
604→		var text string
605→		if err := json.Unmarshal(content, &text); err == nil {
606→			return text
607→		}
608→		return ""
609→	}
610→
611→	if blocksFirst {
612→		if s := tryBlocks(); s != "" {
613→			return s
614→		}
615→		return tryString()
616→	}
617→	if s := tryString(); s != "" {
618→		return s
619→	}
620→	return tryBlocks()
621→}
622→
623→func extractUserPrompt(content json.RawMessage) string {
624→	if len(content) == 0 {
625→		return ""
626→	}
627→
628→	var promptContent kiroPromptContent
629→	if err := json.Unmarshal(content, &promptContent); err == nil && promptContent.Prompt.Prompt != "" {
630→		return promptContent.Prompt.Prompt
631→	}
632→	return ""
633→}
