635→func extractModifiedFilesFromHistory(entries []kiroHistoryEntry) []string {
636→	seen := make(map[string]bool)
637→	var files []string
638→
639→	for i := range entries {
640→		for _, path := range extractFilesFromAssistant(entries[i].Assistant) {
641→			if path == "" || seen[path] {
642→				continue
643→			}
644→			seen[path] = true
645→			files = append(files, path)
646→		}
647→	}
648→
649→	return files
650→}
651→
652→func extractFilesFromAssistant(raw json.RawMessage) []string {
653→	if len(raw) == 0 {
654→		return nil
655→	}
656→
657→	var toolUseContent kiroToolUseContent
658→	if err := json.Unmarshal(raw, &toolUseContent); err != nil || len(toolUseContent.ToolUse.ToolUses) == 0 {
659→		return nil
660→	}
661→
662→	var paths []string
663→	for _, call := range toolUseContent.ToolUse.ToolUses {
664→		if !isFileModificationTool(call.Name) {
665→			continue
666→		}
667→		if path := extractFilePath(call.Args); path != "" {
668→			paths = append(paths, path)
669→		}
670→	}
671→	return paths
672→}
673→
674→func isFileModificationTool(name string) bool {
675→	_, ok := kiroFileModificationTools[name]
676→	return ok
677→}
678→
679→func extractFilePath(args json.RawMessage) string {
680→	if len(args) == 0 {
681→		return ""
682→	}
683→
684→	var fields map[string]json.RawMessage
685→	if err := json.Unmarshal(args, &fields); err != nil {
686→		return ""
687→	}
688→
689→	for _, key := range []string{"path", "file_path", "filename"} {
690→		raw, ok := fields[key]
691→		if !ok {
692→			continue
693→		}
694→		var path string
695→		if err := json.Unmarshal(raw, &path); err == nil && path != "" {
696→			return path
697→		}
698→	}
699→	return ""
700→}
