820→// convertExecutionActionsToHistoryEntries converts Kiro IDE execution log
821→// actions into CLI transcript history entries. Tool-modifying actions (create,
822→// edit) become ToolUse entries; say actions become Response entries.
823→func convertExecutionActionsToHistoryEntries(actions []kiroExecutionAction) []kiroHistoryEntry {
824→	var toolCalls []kiroToolCall
825→	var entries []kiroHistoryEntry
826→
827→	for _, action := range actions {
828→		if toolName, ok := execActionToToolName[action.ActionType]; ok {
829→			filePath := extractExecActionFilePath(action.Input)
830→			if filePath != "" {
831→				args, _ := json.Marshal(map[string]string{"path": filePath})
832→				toolCalls = append(toolCalls, kiroToolCall{
833→					Name: toolName,
834→					Args: args,
835→				})
836→			}
837→		}
838→		if action.ActionType == "say" {
839→			var out struct {
840→				Message string `json:"message"`
841→			}
842→			if err := json.Unmarshal(action.Output, &out); err == nil && out.Message != "" {
843→				// Flush any pending tool calls first
844→				if len(toolCalls) > 0 {
845→					toolUseJSON, _ := json.Marshal(kiroToolUseContent{
846→						ToolUse: kiroToolUsePayload{ToolUses: toolCalls},
847→					})
848→					entries = append(entries, kiroHistoryEntry{Assistant: toolUseJSON})
849→					toolCalls = nil
850→				}
851→				responseJSON, _ := json.Marshal(kiroResponseContent{
852→					Response: kiroResponsePayload{Content: out.Message},
853→				})
854→				entries = append(entries, kiroHistoryEntry{Assistant: responseJSON})
855→			}
856→		}
857→	}
858→
859→	// Flush remaining tool calls without a trailing say
860→	if len(toolCalls) > 0 {
861→		toolUseJSON, _ := json.Marshal(kiroToolUseContent{
862→			ToolUse: kiroToolUsePayload{ToolUses: toolCalls},
863→		})
864→		entries = append(entries, kiroHistoryEntry{Assistant: toolUseJSON})
865→	}
866→
867→	return entries
868→}
