870→// extractExecActionFilePath extracts the file path from an execution log
871→// action's input JSON (used by create/edit actions).
872→func extractExecActionFilePath(input json.RawMessage) string {
873→	if len(input) == 0 {
874→		return ""
875→	}
876→	var fields struct {
877→		File string `json:"file"`
878→	}
879→	if err := json.Unmarshal(input, &fields); err != nil {
880→		return ""
881→	}
882→	return fields.File
883→}
884→
885→// enrichIDETranscriptWithExecutionLogs converts an IDE transcript to CLI
886→// format and replaces "On it." assistant entries with actual data from
887→// execution logs. Returns the re-serialized CLI-format JSON, or nil if
888→// conversion fails.
889→func enrichIDETranscriptWithExecutionLogs(ideData []byte, execLogs map[string]*kiroExecutionLog) []byte {
890→	var meta kiroIDESessionMeta
891→	if err := json.Unmarshal(ideData, &meta); err != nil {
892→		return nil
893→	}
894→
895→	// Also parse the IDE transcript for the basic user/assistant pairing
896→	var ide kiroIDETranscript
897→	if err := json.Unmarshal(ideData, &ide); err != nil {
898→		return nil
899→	}
900→
901→	// Build an executionId→index mapping from the meta history
902→	execIDMap := make(map[int]string) // IDE history index → executionId
903→	for i, entry := range meta.History {
904→		if entry.ExecutionID != "" {
905→			execIDMap[i] = entry.ExecutionID
906→		}
907→	}
908→
909→	// Convert to CLI format, enriching assistant entries from execution logs
910→	transcript := &kiroTranscript{}
911→	var pendingUser *kiroIDEHistoryEntry
912→	for i := range ide.History {
913→		entry := &ide.History[i]
914→		switch entry.Message.Role {
915→		case "user":
916→			if pendingUser != nil {
917→				transcript.History = append(transcript.History, ideEntryToPaired(pendingUser, nil))
918→			}
919→			pendingUser = entry
920→		case "assistant":
921→			execID := execIDMap[i]
922→			if execID != "" {
923→				if execLog, ok := execLogs[execID]; ok {
924→					// Replace with execution log data
925→					userEntry := ideEntryToPaired(pendingUser, nil)
926→					assistantEntries := convertExecutionActionsToHistoryEntries(execLog.Actions)
927→					if len(assistantEntries) > 0 {
928→						// First entry gets the user prompt
929→						userEntry.Assistant = assistantEntries[0].Assistant
930→						transcript.History = append(transcript.History, userEntry)
931→						// Additional entries (if tool calls + response) get appended
932→						for _, extra := range assistantEntries[1:] {
933→							transcript.History = append(transcript.History, extra)
934→						}
935→						pendingUser = nil
936→						continue
937→					}
938→				}
939→			}
940→			// Fallback: use the IDE text as-is
941→			transcript.History = append(transcript.History, ideEntryToPaired(pendingUser, entry))
942→			pendingUser = nil
943→		}
944→	}
945→	if pendingUser != nil {
946→		transcript.History = append(transcript.History, ideEntryToPaired(pendingUser, nil))
947→	}
948→
949→	result, err := json.Marshal(transcript)
950→	if err != nil {
951→		return nil
952→	}
953→	return result
954→}
