 50→func (a *Agent) ChunkTranscript(content []byte, maxSize int) ([][]byte, error) {
 51→	if maxSize <= 0 {
 52→		return nil, errors.New("max-size must be greater than zero")
 53→	}
 54→	if len(content) == 0 {
 55→		return [][]byte{[]byte{}}, nil
 56→	}
 57→
 58→	var chunks [][]byte
 59→	for start := 0; start < len(content); start += maxSize {
 60→		end := start + maxSize
 61→		if end > len(content) {
 62→			end = len(content)
 63→		}
 64→		chunk := make([]byte, end-start)
 65→		copy(chunk, content[start:end])
 66→		chunks = append(chunks, chunk)
 67→	}
 68→	return chunks, nil
 69→}
