122→	if conversationID != "" {
123→		query = fmt.Sprintf(
124→			"SELECT value FROM conversations_v2 WHERE json_extract(value, '$.conversation_id') = '%s' ORDER BY updated_at DESC LIMIT 1",
125→			escapeSQLString(conversationID),
126→		)
127→	} else {
128→		query = fmt.Sprintf(
129→			"SELECT value FROM conversations_v2 WHERE key = '%s' ORDER BY updated_at DESC LIMIT 1",
130→			escapeSQLString(cwd),
131→		)
132→	}
133→
134→	out, err := runSQLiteCommand(db, query)
135→	if err != nil {
136→		return "", fmt.Errorf("sqlite3 transcript query failed: %w", err)
137→	}
138→
139→	raw := strings.TrimSpace(string(out))
140→	if raw == "" {
141→		return "", errors.New("no transcript found")
142→	}
143→
144→	cachePath, err := a.cacheTranscriptPath(cwd, sessionID)
145→	if err != nil {
146→		return "", err
147→	}
148→
149→	data := []byte(raw)
150→	if filtered, ok := a.trimTranscriptHistory([]byte(raw)); ok {
151→		data = filtered
152→	}
153→
154→	// If the transcript has no history (e.g., offset trimmed everything),
155→	// return error so captureTranscriptForStop can try other sources (IDE).
156→	if parsed, parseErr := parseTranscript(data); parseErr == nil && len(parsed.History) == 0 {
157→		return "", errors.New("CLI transcript has no history entries")
158→	}
159→
160→	if err := os.WriteFile(cachePath, data, 0o600); err != nil {
161→		return "", fmt.Errorf("failed to write cached transcript: %w", err)
162→	}
163→	return cachePath, nil
164→}
