336→func (a *Agent) captureTranscriptForStop(cwd string, sessionID string, conversationID string) string {
337→	// Try IDE workspace sessions first — the stop hook is fired by the IDE,
338→	// so IDE data is the most accurate source. CLI DB is a fallback for
339→	// kiro-cli (non-IDE) sessions where no IDE workspace data exists.
340→	if sessionRef, err := a.ensureIDETranscript(cwd, sessionID); err == nil && sessionRef != "" {
341→		return sessionRef
342→	}
343→	if sessionRef, err := a.ensureCachedTranscript(cwd, sessionID, conversationID); err == nil && sessionRef != "" {
344→		return sessionRef
345→	}
346→	return a.createPlaceholderTranscript(cwd, sessionID)
347→}
