760→// findExecutionLogsForSession scans Kiro IDE workspace directories to find
761→// execution log files matching the given chat session ID. Returns a map of
762→// executionId → *kiroExecutionLog.
763→func findExecutionLogsForSession(chatSessionID string) (map[string]*kiroExecutionLog, error) {
764→	baseDir, err := ideExecutionLogsBaseDir()
765→	if err != nil {
766→		return nil, err
767→	}
768→
769→	entries, err := os.ReadDir(baseDir)
770→	if err != nil {
771→		return nil, err
772→	}
773→
774→	for _, entry := range entries {
775→		if !entry.IsDir() || len(entry.Name()) != 32 {
776→			continue
777→		}
778→		logsDir := filepath.Join(baseDir, entry.Name(), execLogsSubdir)
779→		if _, err := os.Stat(logsDir); err != nil {
780→			continue
781→		}
782→		logs := scanExecutionLogsDir(logsDir, chatSessionID)
783→		if len(logs) > 0 {
784→			return logs, nil
785→		}
786→	}
787→
