791→// scanExecutionLogsDir reads all execution log files in a directory and returns
792→// those matching the given chat session ID.
793→func scanExecutionLogsDir(dir string, chatSessionID string) map[string]*kiroExecutionLog {
794→	files, err := os.ReadDir(dir)
795→	if err != nil {
796→		return nil
797→	}
798→
799→	result := make(map[string]*kiroExecutionLog)
800→	for _, f := range files {
801→		if f.IsDir() {
802→			continue
803→		}
804→		data, err := os.ReadFile(filepath.Join(dir, f.Name()))
805→		if err != nil {
806→			continue
807→		}
808→		var log kiroExecutionLog
809→		if err := json.Unmarshal(data, &log); err != nil {
810→			continue
811→		}
812→		if log.ChatSessionID == chatSessionID {
813→			logCopy := log
814→			result[log.ExecutionID] = &logCopy
815→		}
816→	}
817→	return result
818→}
