893→// createIDEWorkspaceSessionsDirRealEncoding creates an IDE workspace sessions
894→// directory using the encoding the Kiro IDE actually uses: standard base64
895→// with '=' padding replaced by '_'.
896→func createIDEWorkspaceSessionsDirRealEncoding(t *testing.T, home string, cwd string) string {
897→	t.Helper()
898→	encoded := strings.ReplaceAll(base64.StdEncoding.EncodeToString([]byte(cwd)), "=", "_")
899→	var dir string

 900→	switch runtime.GOOS {
 901→	case "darwin":
 902→		dir = filepath.Join(home, "Library", "Application Support", "Kiro", "User", "globalStorage", "kiro.kiroagent", "workspace-sessions", encoded)
 903→	default:
 904→		dir = filepath.Join(home, ".config", "Kiro", "User", "globalStorage", "kiro.kiroagent", "workspace-sessions", encoded)
 905→	}
 906→	if err := os.MkdirAll(dir, 0o750); err != nil {
 907→		t.Fatalf("mkdir sessions dir: %v", err)
 908→	}
 909→	return dir
 910→}
