	if err != nil {
		t.Fatalf("read cached transcript: %v", err)
	}

	// Should be in CLI format with tool calls merged
	var result kiroTranscript
	if err := json.Unmarshal(data, &result); err != nil {
		t.Fatalf("parse cached transcript: %v", err)
	}

