// createIDEWorkspaceSessionsDirRealEncoding creates an IDE workspace sessions
// directory using the encoding the Kiro IDE actually uses: standard base64
// with '=' padding replaced by '_'.
func createIDEWorkspaceSessionsDirRealEncoding(t *testing.T, home string, cwd string) string {
	t.Helper()
	encoded := strings.ReplaceAll(base64.StdEncoding.EncodeToString([]byte(cwd)), "=", "_")
	var dir string
	switch runtime.GOOS {
	case "darwin":
		dir = filepath.Join(home, "Library", "Application Support", "Kiro", "User", "globalStorage", "kiro.kiroagent", "workspace-sessions", encoded)
	default:
		dir = filepath.Join(home, ".config", "Kiro", "User", "globalStorage", "kiro.kiroagent", "workspace-sessions", encoded)
	}
	if err := os.MkdirAll(dir, 0o750); err != nil {
		t.Fatalf("mkdir sessions dir: %v", err)
	}
	return dir
}

