	}

	// Tool calls JSONL should be consumed (deleted)
	if _, err := os.Stat(filepath.Join(toolCallsDir, toolCallsFile)); !os.IsNotExist(err) {
		t.Fatal("tool calls JSONL should be deleted after consumption")
	}
}

